INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'overview', 'Overview > Facts: NIT Andhra Pradesh (NITAP) is located at Ganesh Nagar, Tadepalligudem, West Godavari, Andhra Pradesh 534101. Full name: National Institute of Technology Andhra Pradesh.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'transport', 'Transport > Bus Stand: 5 km from NIT Andhra Pradesh campus');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'transport', 'Transport > Railway Station: 7 km from NIT Andhra Pradesh campus');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'transport', 'Transport > Airport: Rajahmundry Airport, 50 km from NIT Andhra Pradesh campus');
