INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'hostels', 'Hostels > Summary: 10 boys hostels and 5 girls hostels at NIT Andhra Pradesh. Room sharing decreases from 4 per room in 1st year to single rooms in 4th year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'mess', 'Mess > Full 7-day schedule available for both boys and girls mess at NIT Andhra Pradesh. Amrutha Mess serves girls. Covers breakfast, lunch, snacks, and dinner daily.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'fee_structure', 'Fee Structure > Odd Semester: Library Fee Rs 2,400, Exam Fee Rs 2,400, Other Fee Rs 2,400. Tuition: Rs 62,500 (General income >5L), Rs 20,833 (income 1-5L), Rs 0 (SC/ST or income <1L).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'fee_structure', 'Fee Structure > Even Semester: Similar structure to odd semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'fee_structure', 'Fee Structure > Notes: ARB and OEB students must pay full tuition during admission and semester registration. Fee payment through Central Easy Pay.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'hostel_fee', 'Hostel Fee > For 1st Year B.Tech AY 2023-24: Includes Hostel Caution Deposit, Room Charges, Establishment Charges, Mess Security Deposit. Maintenance Rs 140/day.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'wifi', 'WiFi > Facts: WiFi facility available at NIT Andhra Pradesh. Airtel and Jio 5G/4G connectivity available.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'attendance', 'Attendance > Facts: 80% attendance is mandatory at NIT Andhra Pradesh.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'clubs', 'Clubs > List: Dhvani, Painting and Photography, Robotics, Career Guidance, Literature and Debate, I&E Cell, Nature Club, Brindavanam Club, Bhavisya Bharat, Shilpi. Total 10 clubs.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'fests', 'Fests > Odd Semester: Techkriya (September/October). Even Semester: Vulcanzy (February).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'laundry', 'Laundry > Dhobi available on campus at NIT Andhra Pradesh. Dhobi Ghaat (clothes washing area) also available.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'elections', 'Elections > No student elections at NIT Andhra Pradesh.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'sports', 'Sports > Available: Cricket, Badminton, Football, Basketball, Kabaddi, Kho-Kho, Chess, Tennis, Carroms, Tug of War, Weightlifting.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'canteen', 'Canteen > Dokka Seethamma Canteen at NIT Andhra Pradesh, open 9 AM to 10 PM. Fast food and stationery shops also available on campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'fines', 'Fines > Late registration starts from Rs 500. Kettle usage fine Rs 10,000-20,000. Alcohol consumption fine Rs 10,000-30,000 plus suspension for a week.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'gym', 'Gym > Common gym available at NIT Andhra Pradesh. Not free.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Andhra Pradesh', 'medical', 'Medical > Dispensary within walkable distance from NIT Andhra Pradesh campus. Free of cost.');
